const sd = $getWorkflowStaticData('global');
if (!sd.chats) sd.chats = {};
const inp = $input.first().json;
const isCb = !!inp.callback_query;
const chatId = isCb ? inp.callback_query.message.chat.id : inp.message?.chat?.id;
const text = isCb ? '' : (inp.message?.text || '').trim();
const cb = isCb ? inp.callback_query.data : '';
const cbId = isCb ? inp.callback_query.id : '';
const st = sd.chats[chatId] || {};
const r = { action:'reply', chatId, text:'', kb:null, cbId, title:'', type:'', subType:'', raw:'', cId:'' };

const MENU = [[{text:'📝 Buat Konten',callback_data:'m_create'},{text:'📊 Cek Status',callback_data:'m_status'}],[{text:'📤 Submit Review',callback_data:'m_submit'},{text:'🖼 Prompt Thumbnail',callback_data:'m_thumb'}],[{text:'🔗 Buka Web Adably',url:'https://adably.id/admin'},{text:'❓ Bantuan',callback_data:'m_help'}]];

const TYPES = [[{text:'❓ QNA',callback_data:'t_QNA'},{text:'📝 Artikel',callback_data:'t_ARTICLE'}],[{text:'📚 Pembelajaran',callback_data:'t_PEMBELAJARAN'},{text:'📖 Kisah',callback_data:'t_KISAH'}],[{text:'◀️ Menu',callback_data:'m_main'}]];

const KISAH = [[{text:'🕌 Sirah Nabawiyah',callback_data:'k_SIRAH'}],[{text:'📜 Qashashul Anbiya',callback_data:'k_QASHASH'}],[{text:'⭐ Teladan Sahabat',callback_data:'k_TELADAN'}],[{text:'✨ Cerita Fiksi',callback_data:'k_FIKSI'}],[{text:'◀️ Kembali',callback_data:'m_create'}]];

const RATIO = [[{text:'🖥 16:9 Website',callback_data:'r_16:9'}],[{text:'📱 1:1 IG/FB',callback_data:'r_1:1'}],[{text:'📲 4:5 IG Optimal',callback_data:'r_4:5'}],[{text:'◀️ Menu',callback_data:'m_main'}]];

function prompt(type, sub, title) {
  const base = `Buatkan konten islami untuk anak (usia 3-10 tahun) dengan judul: "${title}"

Gunakan format marker berikut untuk setiap bagian:

`;
  if (type === 'QNA') return base + '(quick_answer)
Jawaban singkat 1-2 kalimat

(paragraph)
Penjelasan detail yang mudah dipahami anak

(dalil)
Arab: (teks arab dalil)
Terjemahan: (terjemahan indonesia)
Sumber: (sumber hadits/ayat)

(analogy)
Judul: (judul analogi)
Analogi sederhana menggunakan benda/pengalaman sehari-hari anak

(doa)
Judul: (judul doa)
Arab: (teks arab doa)
Terjemahan: (terjemahan)
Sumber: (sumber)

(tip)
Tips praktis yang bisa dilakukan anak';
  if (type === 'ARTICLE') return base + '(paragraph)
Paragraf pembuka yang menarik

(paragraph)
Isi artikel - penjelasan mendalam

(dalil)
Arab: (teks arab)
Terjemahan: (terjemahan)
Sumber: (sumber)

(analogy)
Judul: (judul analogi)
Analogi untuk memudahkan pemahaman

(tip)
Tips praktis untuk anak';
  if (type === 'PEMBELAJARAN') return base + '(paragraph)
Pengantar materi pembelajaran

(paragraph)
Penjelasan materi utama

(dalil)
Arab: (teks arab)
Terjemahan: (terjemahan)
Sumber: (sumber)

(analogy)
Judul: (judul analogi)
Analogi untuk mempermudah belajar

(hikmah)
Hikmah dan pelajaran

(tip)
Tips belajar untuk anak';
  if (type === 'KISAH') {
    const subLabel = {SIRAH:'Sirah Nabawiyah',QASHASH:'Qashashul Anbiya',TELADAN:'Teladan Sahabat/Ulama',FIKSI:'Cerita Fiksi Islami'}[sub] || sub;
    return `Buatkan kisah islami "${subLabel}" untuk anak (3-10 tahun)
Judul: "${title}"
Gaya: pencerita — panjang, mengalir, penuh detail
Min 600 kata

Format:
(paragraph)
Narasi kisah bagian 1

(paragraph)
Narasi kisah bagian 2

(paragraph)
Narasi kisah bagian 3

(hikmah)
Hikmah dari kisah ini

(doa)
Judul: (judul doa)
Arab: (teks arab)
Terjemahan: (terjemahan)
Sumber: (sumber)

ATURAN: ${sub==='FIKSI'?'Karakter fiktif, nilai Islam terselip alami, setting kehidupan anak muslim':'Ikuti HANYA fakta dari sumber mu'tabar. JANGAN tambahkan kejadian fiktif. Cantumkan sumber setiap dialog/riwayat.'}`;
  }
  return base + '(paragraph)
Konten utama';
}

function thumbPrompt(ratio, title) {
  const size = {'16:9':'1280x720 landscape','1:1':'1080x1080 square','4:5':'1080x1350 portrait'}[ratio];
  return `Buatkan thumbnail bergaya kartun islami anak-anak.
Tema: "${title}"
Rasio: ${ratio} (${size})
Style: kartun lucu, warna cerah & vibrant, cocok edukasi Islam anak
Tidak ada teks di dalam gambar.
Background: simple, clean, eye-catching`;
}

if (isCb) {
  switch(cb) {
    case 'm_main': r.text='👋 *Menu Utama*
Pilih menu:'; r.kb=MENU; break;
    case 'm_create': r.text='📝 *Pilih tipe konten:*'; r.kb=TYPES; break;
    case 'm_status': sd.chats[chatId]={step:'wait_status_id'}; r.text='📊 Ketik ID konten:'; break;
    case 'm_submit': sd.chats[chatId]={step:'wait_submit_id'}; r.text='📤 Ketik ID konten yang ingin diajukan review:'; break;
    case 'm_thumb': r.text='🖼 *Pilih rasio thumbnail:*'; r.kb=RATIO; break;
    case 'm_help': r.text='❓ *Panduan Adably Bot*

1️⃣ Klik 📝 Buat Konten → pilih tipe
2️⃣ Ketik judul → bot kirim prompt
3️⃣ Copy prompt → paste ke Gemini
4️⃣ Kirim hasil Gemini ke bot
5️⃣ Bot simpan otomatis ke DRAFT
6️⃣ Klik Submit Review

🖼 Untuk thumbnail → pilih rasio → ketik judul → copy prompt ke AI image generator → upload manual di web Adably'; r.kb=[[{text:'◀️ Menu',callback_data:'m_main'}]]; break;
    case 't_QNA': case 't_ARTICLE': case 't_PEMBELAJARAN':
      const tp=cb.replace('t_',''); sd.chats[chatId]={step:'wait_title',type:tp};
      r.text=`✅ Tipe: *${tp}*

✏️ Ketik judul konten:`; break;
    case 't_KISAH': r.text='📖 *Pilih sub-tipe Kisah:*'; r.kb=KISAH; break;
    case 'k_SIRAH': case 'k_QASHASH': case 'k_TELADAN': case 'k_FIKSI':
      const ks=cb.replace('k_',''); sd.chats[chatId]={step:'wait_title',type:'KISAH',sub:ks};
      r.text=`✅ Kisah: *${ks}*

✏️ Ketik judul kisah:`; break;
    case 'r_16:9': case 'r_1:1': case 'r_4:5':
      const rt=cb.replace('r_',''); sd.chats[chatId]={step:'wait_thumb_title',ratio:rt};
      r.text=`✅ Rasio: *${rt}*

✏️ Ketik judul/tema thumbnail:`; break;
    default:
      if(cb.startsWith('submit_')){r.action='submit';r.cId=cb.replace('submit_','');}
      else if(cb.startsWith('status_')){r.action='status';r.cId=cb.replace('status_','');}
      else{r.text='❓ Perintah tidak dikenali';r.kb=MENU;}
  }
} else if (text.startsWith('/start')) {
  r.text='👋 *Assalamu'alaikum!*

Saya *Adably Content Bot* 🤖
Asisten pembuatan konten islami anak.

Pilih menu:'; r.kb=MENU;
} else if (st.step === 'wait_title') {
  const p = prompt(st.type, st.sub, text);
  sd.chats[chatId] = {step:'wait_content',type:st.type,sub:st.sub,title:text};
  r.text=`📋 *Prompt ${st.type}*
_"${text}"_

\`\`\`
${p}
\`\`\`

👆 Copy → paste ke Gemini → kirim hasilnya ke sini`;
} else if (st.step === 'wait_content') {
  r.action='save'; r.type=st.type; r.title=st.title; r.raw=text;
  delete sd.chats[chatId];
} else if (st.step === 'wait_thumb_title') {
  const tp = thumbPrompt(st.ratio, text);
  delete sd.chats[chatId];
  r.text=`🖼 *Prompt Thumbnail ${st.ratio}*
_"${text}"_

\`\`\`
${tp}
\`\`\`

👆 Copy → paste ke AI image generator
Lalu upload manual di web Adably`;
  r.kb=[[{text:'🖼 Rasio Lain',callback_data:'m_thumb'},{text:'◀️ Menu',callback_data:'m_main'}]];
} else if (st.step === 'wait_status_id') {
  r.action='status'; r.cId=text.trim(); delete sd.chats[chatId];
} else if (st.step === 'wait_submit_id') {
  r.action='submit'; r.cId=text.trim(); delete sd.chats[chatId];
} else {
  r.text='🤔 Saya tidak mengerti pesan ini.
Gunakan menu di bawah:'; r.kb=MENU;
}

return [{json:r}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const ok = res.success;
const id = res.data?.id || '';
const kb = ok ? [[{text:'📤 Submit Review',callback_data:'submit_'+id},{text:'📊 Status',callback_data:'status_'+id}],[{text:'🔗 Buka Editor',url:'https://adably.id/admin/editor?id='+id},{text:'◀️ Menu',callback_data:'m_main'}]] : [[{text:'◀️ Menu',callback_data:'m_main'}]];
const text = ok ? `✅ *Konten tersimpan!*\n\nID: \`${id}\`\nJudul: ${res.data?.title}\nStatus: ${res.data?.status}\nTipe: ${res.data?.type}` : `❌ Gagal menyimpan: ${res.message||'Error'}`;
return [{json:{chatId:prev.chatId,text,kb}}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const text = res.success ? `✅ ${res.message}` : `❌ ${res.message||'Gagal submit'}`;
const kb = [[{text:'📊 Cek Status',callback_data:'status_'+prev.cId},{text:'◀️ Menu',callback_data:'m_main'}]];
return [{json:{chatId:prev.chatId,text,kb}}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const d = res.data || {};
const text = res.success ? `📊 *Status Konten*

ID: \`${d.id}\`
Judul: ${d.title}
Tipe: ${d.type}
Status: ${d.status}
Update: ${d.updatedAt?.substring(0,10)||'-'}
Thumbnail: ${d.thumbnailUrl?'✅':'❌'}` : `❌ ${res.message||'Tidak ditemukan'}`;
const kb = res.success ? [[{text:'📤 Submit',callback_data:'submit_'+d.id},{text:'🔗 Editor',url:'https://adably.id/admin/editor?id='+d.id}],[{text:'◀️ Menu',callback_data:'m_main'}]] : [[{text:'◀️ Menu',callback_data:'m_main'}]];
return [{json:{chatId:prev.chatId,text,kb}}];
